const chunkSize = 500;
const chunkOverlap = 80;

function chunkText(text, size, overlap) {
  const chunks = [];
  let start = 0;
  while (start < text.length) {
    const end = Math.min(text.length, start + size);
    let chunk = text.slice(start, end);
    const lastPeriod = chunk.lastIndexOf('.');
    if (end < text.length && lastPeriod > size * 0.4) {
      chunk = chunk.slice(0, lastPeriod + 1);
    }
    chunk = chunk.trim();
    if (chunk.length) chunks.push(chunk);
    start = start + size - overlap;
  }
  return chunks;
}

const output = [];
for (const item of $input.all()) {
  const doc = item.json;
  const content = doc.pageContent || "";
  const meta = doc.metadata || {};
  const baseId = meta.source || `doc_${Math.random().toString(36).slice(2)}`;

  const chunks = chunkText(content, chunkSize, chunkOverlap);

  chunks.forEach((chunk, idx) => {
    const chunkId = `${baseId}_chunk_${idx}`;

    // Content
    output.push({ json: { pageContent: chunk, metadata: { ...meta, chunk_id: chunkId, embedding_role: "content" }}});

    // Title
    const title = (chunk.split("\n")[0] || "").slice(0, 120).trim();
    if (title) output.push({ json: { pageContent: title, metadata: { ...meta, chunk_id: chunkId, embedding_role: "title" }}});

    // Keywords
    const kw = (meta.keywords || []).join(", ").slice(0, 200);
    if (kw) output.push({ json: { pageContent: kw, metadata: { ...meta, chunk_id: chunkId, embedding_role: "keywords" }}});
  });
}
return output;

const TECH_TERMS = ["tduid", "tdconv", "trsdk", "datalayer", "cname", "dns", "gtm", "ordervalue", "transactionid", "xml", "csv", "sku", "ean"];

function classify(text) {
  const t = text.toLowerCase();
  if (t.includes("dns")) return "dns-setup";
  if (t.includes("branded tracking") || t.includes("first-party")) return "branded-tracking";
  if (t.includes("confirmation")) return "conversion-tracking";
  if (t.includes("gtm")) return "gtm-implementation";
  if (t.includes("feed")) return "product-feed";
  if (t.includes("consent") || t.includes("gdpr")) return "compliance";
  if (t.includes("test")) return "testing";
  return "general";
}

const now = new Date().toISOString();
const out = [];

for (const item of $input.all()) {
  const doc = item.json;
  const content = (doc.pageContent || "").toLowerCase();
  const meta = doc.metadata || {};

  const autoKeywords = TECH_TERMS.filter(term => content.includes(term.toLowerCase()));
  const allKeywords = [...new Set([...(meta.keywords || []), ...autoKeywords])];

  const semanticCategory = classify(content);

  const searchText = [meta.category, meta.topic, meta.subtopic, semanticCategory, allKeywords.join(" "), (doc.pageContent || "").slice(0, 300)].filter(Boolean).join(" ");

  out.push({ json: { ...doc, metadata: { ...meta, keywords: allKeywords, semantic_category: semanticCategory, search_text: searchText, last_updated: now }}});
}
return out;
